prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?taskAName ?taskBName ?betweenName ?betweenId WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "f404135647444aedabe98bb54c000517" .

  ?between a bboExt:ChoreographyTask ;
           tai:belongsTo ?choreo ;
           bbo:name ?betweenName ;
           bbo:id ?betweenId .

  ?taskA a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?taskAName .
  ?taskB a bboExt:ChoreographyTask ;
         tai:belongsTo ?choreo ;
         bbo:name ?taskBName .

  FILTER(CONTAINS(LCASE(STR(?taskAName)), LCASE("Cancellation Acknowledge")))
  FILTER(CONTAINS(LCASE(STR(?taskBName)), LCASE("Notification")))
  FILTER(?between != ?taskA && ?between != ?taskB)

  # between is reachable from A
  ?taskA (^bbo:has_sourceRef)/bbo:has_targetRef+ ?between .
  # and B is reachable from between
  ?between (^bbo:has_sourceRef)/bbo:has_targetRef+ ?taskB .
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?name ?id ?choreo WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "f404135647444aedabe98bb54c000517" ;
         tai:belongsTo ?org .
  ?def tai:belongsTo ?model ;
       bboExt:hasChoreography ?choreo .
  ?choreo a bboExt:Choreography .
  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:id ?id .
  OPTIONAL { ?task bbo:name ?name . }
  FILTER( (BOUND(?name) && CONTAINS(LCASE(STR(?name)), LCASE("cancellation acknowledge"))))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?model ?propVal ?propName ?choreoName ?choreo WHERE {
  VALUES ?propName { "tai:normalizedId" "tai:originalId" "bbo:name" }
  ?model a bboExt:Model ;
         ?p ?propVal .
  FILTER(
    ( ?p = tai:normalizedId && STR(?propVal) = "f404135647444aedabe98bb54c000517" )
    ||( ?p = tai:originalId   && STR(?propVal) = "f404135647444aedabe98bb54c000517" )
    ||( ?p = bbo:name && CONTAINS(LCASE(STR(?propVal)), "f404135647444aedabe98bb54c000517") )
  )

  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?task ?id ?name ?choreoName WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "f404135647444aedabe98bb54c000517" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .
  OPTIONAL { ?choreo bbo:name ?choreoName . }

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:id ?id .
  OPTIONAL { ?task bbo:name ?name . }

  FILTER(
    (BOUND(?name) && CONTAINS(LCASE(STR(?name)), "cancellation"))
    ||(BOUND(?name) && CONTAINS(LCASE(STR(?name)), "acknowledge"))
    ||(BOUND(?name) && CONTAINS(LCASE(STR(?name)), "notification"))
  )
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT ?elem ?id ?name ?type WHERE {
  ?model a bboExt:Model ;
         tai:normalizedId "f404135647444aedabe98bb54c000517" .
  ?defs tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?defs .

  ?elem tai:belongsTo ?choreo ;
        bbo:name ?name .
  OPTIONAL { ?elem bbo:id ?id . }
  ?elem a ?type .

  FILTER(
    CONTAINS(LCASE(STR(?name)), "cancellation")
    ||CONTAINS(LCASE(STR(?name)), "acknowledge")
    ||CONTAINS(LCASE(STR(?name)), "notification")
  )
}
LIMIT 25
